using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig()
    {
        var config = new
        {
            Environment = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false },
            Version = "1.0.0"
        };

        return JsonSerializer.Serialize(config, JsonOptions);
    }

    [McpServerResource(
        UriTemplate = "config://endpoints",
        Name = "API Endpoints",
        MimeType = "application/json"),
     Description("Returns the list of configured API endpoints.")]
    public static string GetEndpoints()
    {
        var endpoints = new[]
        {
            new { Name = "Users",    Url = "https://api.example.com/users",    Method = "GET" },
            new { Name = "Products", Url = "https://api.example.com/products", Method = "GET" },
            new { Name = "Orders",   Url = "https://api.example.com/orders",   Method = "POST" }
        };

        return JsonSerializer.Serialize(endpoints, JsonOptions);
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Looks up the value of a configuration key by name.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. MaxRetries, TimeoutSeconds)")] string key)
    {
        var settings = new Dictionary<string, object>(StringComparer.OrdinalIgnoreCase)
        {
            ["MaxRetries"] = 3,
            ["TimeoutSeconds"] = 30,
            ["Environment"] = Environment.GetEnvironmentVariable("ASPNETCORE_ENVIRONMENT") ?? "Production",
            ["Version"] = "1.0.0",
            ["DarkMode"] = true,
            ["BetaAccess"] = false
        };

        return settings.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Unknown configuration key: {key}";
    }

    [McpServerTool, Description("Lists all available configuration keys.")]
    public static string ListConfigKeys()
    {
        var keys = new[] { "MaxRetries", "TimeoutSeconds", "Environment", "Version", "DarkMode", "BetaAccess" };
        return JsonSerializer.Serialize(keys);
    }
}

